export default function TwentyThreeLabs() {
  const [slide, setSlide] = useState(0);
  const total = testimonials.length;
  const go = (i: number) => setSlide((i + total) % total);

  type FormState = {
    fullName: string;
    company: string;
    email: string;
    phone: string;
    message: string;
    website: string; // honeypot
  };
  type FormErrors = Partial<Record<keyof FormState, string>>;
  type Status = "idle" | "loading" | "success" | "error";

  const emptyForm: FormState = { fullName: "", company: "", email: "", phone: "", message: "", website: "" };
  const [form, setForm] = useState<FormState>(emptyForm);
  const [errors, setErrors] = useState<FormErrors>({});
  const [status, setStatus] = useState<Status>("idle");
  const [serverMsg, setServerMsg] = useState("");

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    const { name, value } = e.target;
    setForm((f) => ({ ...f, [name]: value }));
    setErrors((prev) => (prev[name as keyof FormState] ? { ...prev, [name]: undefined } : prev));
  };

  const validate = (f: FormState): FormErrors => {
    const e: FormErrors = {};
    if (!f.fullName.trim()) e.fullName = "Please enter your name.";
    if (!f.email.trim()) e.email = "Please enter your email address.";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(f.email.trim())) e.email = "Please enter a valid email address.";
    if (!f.message.trim()) e.message = "Please tell us how we can help.";
    return e;
  };

  const handleSubmit = async (ev: React.FormEvent) => {
    ev.preventDefault();
    setServerMsg("");
    const found = validate(form);
    setErrors(found);
    if (Object.keys(found).length > 0) return;

    setStatus("loading");
    try {
      const res = await fetch("/api/contact", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        if (res.status === 422 && data.errors) {
          setErrors(data.errors as FormErrors);
          setStatus("idle");
          return;
        }
        throw new Error(data.error || "Request failed");
      }
      setStatus("success");
      setForm(emptyForm);
    } catch (err) {
      setStatus("error");
      setServerMsg(
        "Something went wrong sending your message. Please try again, or email us directly at hello@23labs.co."
      );
    }
  };

  useEffect(() => {
    const t = setInterval(() => setSlide((s) => (s + 1) % testimonials.length), 6000);
    return () => clearInterval(t);
  }, []);

  useEffect(() => {
    const io = new IntersectionObserver(
      (entries) => entries.forEach((e) => e.isIntersecting && e.target.classList.add("tl-in")),
      { threshold: 0.12 }
    );
    document.querySelectorAll(".tl-reveal").forEach((el) => io.observe(el));
    return () => io.disconnect();
  }, []);

  return (
    <div className="tl-root">
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Poppins:ital,wght@0,100;0,200;0,300;0,400;0,500;0,600;0,700;0,800;0,900;1,100;1,200;1,300;1,400;1,500;1,600;1,700;1,800;1,900&display=swap');${css}`}</style>

      <nav className="tl-nav">
        <div className="tl-nav-in">
          <div className="tl-logo"><img className="tl-logo-img" src={LOGO_SRC} alt="23Labs" /></div>
          <div className="tl-nav-right">
            <div className="tl-nav-links">
              <a href="/about">About</a>
              <a href="/services">Services</a>
              <a href="#work">Work</a>
              <a href="#haylo">Haylo</a>
            </div>
            <a href="/contact" className="tl-nav-cta">Let's have a chat</a>
          </div>
        </div>
      </nav>

      <header
        className="tl-hero"
        style={{
          background: `linear-gradient(90deg, rgba(8,10,20,.85) 0%, rgba(8,10,20,.55) 42%, rgba(8,10,20,.28) 100%), url(${HERO_BG}) center/cover no-repeat`,
        }}
      >
        <div className="tl-wrap" style={{ position: "relative", zIndex: 1 }}>
          <h1 className="tl-hero-h">Helping Businesses Scale With <span className="tl-em">Confidence</span></h1>
          <p className="tl-hero-sub">From everyday operations to customer engagement, we help businesses remove inefficiencies and create systems that support long-term success.</p>
          <div className="tl-hero-actions">
            <a href="#contact" className="tl-btn-primary">Talk to us <span className="tl-btn-arrow" aria-hidden="true">→</span></a>
          </div>
        </div>
      </header>

      <section id="services" className="tl-sec">
        <div className="tl-wrap">
          <div className="tl-sec-head tl-reveal">
            <h2 className="tl-sec-title">How we help <span className="tl-em">modern businesses grow</span></h2>
          </div>
          <div className="tl-svc-grid tl-reveal">
            {services.map((s) => (
              <div className="tl-svc" key={s.num}>
                <div className="tl-svc-ico"><img src={s.iconSrc} alt="" /></div>
                <h3>{s.title}</h3>
                <p>{s.body}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section id="haylo" className="tl-sec" style={{ paddingTop: 0 }}>
        <div className="tl-wrap">
          <div className="tl-haylo tl-reveal">
            <div>
              <span className="tl-haylo-badge">● Our own product</span>
              <h3>Haylo, the AI receptionist that <span className="tl-em-haylo">never misses a call.</span></h3>
              <p>We don't just build for clients. Haylo is our own AI platform that answers every call, books appointments, and handles after-hours, proof we build software that ships and scales.</p>
              <a href="https://gethaylo.co/" target="_blank" rel="noopener noreferrer" className="tl-haylo-cta">Hear a live call</a>
            </div>
            <div className="tl-phone">
              {callRows.map((c, i) => (
                <div className="tl-call-row" key={i}>
                  <div className={`tl-call-dot${c.live ? " tl-live" : ""}`}>{c.dot}</div>
                  <div className="tl-call-meta"><b>{c.title}</b><span>{c.meta}</span></div>
                  <span className={`tl-call-tag${c.green ? " tl-green" : ""}`}>{c.tag}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </section>

      <section id="stats" className="tl-sec" style={{ paddingTop: 24 }}>
        <div className="tl-wrap">
          <div className="tl-stats tl-reveal">
            {stats.map((s, i) => (
              <div className="tl-stat" key={i}>
                <div className="tl-n">{s.n}<span className="tl-plus">{s.sym}</span></div>
                <div className="tl-l">{s.label}</div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section id="work" className="tl-sec">
        <div className="tl-wrap">
          <div className="tl-sec-head tl-reveal">
            <h2 className="tl-sec-title">Trusted By <span className="tl-em">Growing Businesses</span></h2>
          </div>
          <div className="tl-work-grid tl-reveal">
            {work.map((w, i) => (
              <div className="tl-work" key={i} tabIndex={0}>
                <div className="tl-work-inner">
                  <div className="tl-work-face tl-work-front">
                    <div className="tl-work-img">{w.img ? <img src={w.img} alt={w.name} /> : w.label}</div>
                    <div className="tl-work-body">
                      <h4>{w.name}</h4>
                      <div className="tl-chips">{w.chips.map((c) => <span className="tl-chip" key={c}>{c}</span>)}</div>
                    </div>
                  </div>
                  <div className="tl-work-face tl-work-back">
                    <h4>{w.name}</h4>
                    <div className="tl-work-back-block">
                      <span className="tl-work-back-label">The work</span>
                      <p>{w.desc}</p>
                    </div>
                    <div className="tl-work-back-block">
                      <span className="tl-work-back-label">The result</span>
                      <p>{w.result}</p>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section id="quote" className="tl-sec" style={{ background: "var(--card)", borderTop: "1px solid var(--line)", borderBottom: "1px solid var(--line)" }}>
        <div className="tl-wrap">
          <div className="tl-quote-block tl-reveal" style={{ maxWidth: "100%" }}>
            <div className="tl-slider">
              <div className="tl-slider-track" style={{ transform: `translateX(-${slide * 100}%)` }}>
                {testimonials.map((t, i) => {
                  const parts = t.quote.split(t.emph);
                  return (
                    <div className="tl-slide" key={i}>
                      <div className="tl-q" style={{ maxWidth: "74ch" }}>
                        &ldquo;{parts[0]}<span className="tl-em">{t.emph}</span>{parts[1]}&rdquo;
                      </div>
                      <div className="tl-quote-by">
                        <div className="tl-quote-av">{t.initials}</div>
                        <div><b>{t.name}</b><span>{t.role}</span></div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
            <div className="tl-slider-nav">
              <button className="tl-arrow-btn" onClick={() => go(slide - 1)} aria-label="Previous">‹</button>
              <button className="tl-arrow-btn" onClick={() => go(slide + 1)} aria-label="Next">›</button>
              <div className="tl-slider-dots">
                {testimonials.map((_, i) => (
                  <button
                    key={i}
                    className={`tl-dot-btn${i === slide ? " tl-active" : ""}`}
                    onClick={() => go(i)}
                    aria-label={`Go to slide ${i + 1}`}
                  />
                ))}
              </div>
            </div>
          </div>
        </div>
      </section>

      <section id="contact" className="tl-sec tl-contact">
        <div className="tl-wrap">
          <div className="tl-contact-grid tl-reveal">
            <div className="tl-contact-left">
              <h2>Helping Businesses Scale With <span className="tl-em">Confidence</span></h2>
              <p className="tl-lead">Tell us a little about your business and what you're looking to achieve.</p>
              <p className="tl-support">Whether you want to save time, improve the way your team works, attract more customers, or prepare for growth, we'd love to hear from you.</p>
            </div>

            <div className="tl-contact-right">
              <div className="tl-form-card">
                {status === "success" ? (
                  <div className="tl-form-status tl-ok" role="status" aria-live="polite">
                    Thanks for reaching out. We'll be in touch within one business day.
                  </div>
                ) : (
                  <form className="tl-form" onSubmit={handleSubmit} noValidate>
                    {/* Honeypot: hidden from users, bots tend to fill it */}
                    <div className="tl-hp" aria-hidden="true">
                      <label htmlFor="website">Leave this field empty</label>
                      <input
                        id="website"
                        name="website"
                        type="text"
                        tabIndex={-1}
                        autoComplete="off"
                        value={form.website}
                        onChange={handleChange}
                      />
                    </div>

                    <div className="tl-form-row">
                      <div className="tl-field">
                        <label className="tl-label" htmlFor="fullName">Full Name<span className="tl-req">*</span></label>
                        <input
                          id="fullName"
                          name="fullName"
                          type="text"
                          className={`tl-input${errors.fullName ? " tl-invalid" : ""}`}
                          placeholder="Jane Smith"
                          value={form.fullName}
                          onChange={handleChange}
                          required
                          aria-required="true"
                          aria-invalid={!!errors.fullName}
                          aria-describedby={errors.fullName ? "err-fullName" : undefined}
                          autoComplete="name"
                        />
                        {errors.fullName && <span id="err-fullName" className="tl-err">{errors.fullName}</span>}
                      </div>
                      <div className="tl-field">
                        <label className="tl-label" htmlFor="company">Company Name</label>
                        <input
                          id="company"
                          name="company"
                          type="text"
                          className="tl-input"
                          placeholder="Acme Pty Ltd"
                          value={form.company}
                          onChange={handleChange}
                          autoComplete="organization"
                        />
                      </div>
                    </div>

                    <div className="tl-form-row">
                      <div className="tl-field">
                        <label className="tl-label" htmlFor="email">Email Address<span className="tl-req">*</span></label>
                        <input
                          id="email"
                          name="email"
                          type="email"
                          className={`tl-input${errors.email ? " tl-invalid" : ""}`}
                          placeholder="jane@company.com"
                          value={form.email}
                          onChange={handleChange}
                          required
                          aria-required="true"
                          aria-invalid={!!errors.email}
                          aria-describedby={errors.email ? "err-email" : undefined}
                          autoComplete="email"
                        />
                        {errors.email && <span id="err-email" className="tl-err">{errors.email}</span>}
                      </div>
                      <div className="tl-field">
                        <label className="tl-label" htmlFor="phone">Phone Number</label>
                        <input
                          id="phone"
                          name="phone"
                          type="tel"
                          className="tl-input"
                          placeholder="0400 000 000"
                          value={form.phone}
                          onChange={handleChange}
                          autoComplete="tel"
                        />
                      </div>
                    </div>

                    <div className="tl-field">
                      <label className="tl-label" htmlFor="message">How Can We Help?<span className="tl-req">*</span></label>
                      <textarea
                        id="message"
                        name="message"
                        className={`tl-textarea${errors.message ? " tl-invalid" : ""}`}
                        placeholder="Share a few details about what you need and we'll take it from there."
                        value={form.message}
                        onChange={handleChange}
                        required
                        aria-required="true"
                        aria-invalid={!!errors.message}
                        aria-describedby={errors.message ? "err-message" : undefined}
                      />
                      {errors.message && <span id="err-message" className="tl-err">{errors.message}</span>}
                    </div>

                    {status === "error" && (
                      <div className="tl-form-status tl-bad" role="alert">{serverMsg}</div>
                    )}

                    <button type="submit" className="tl-submit" disabled={status === "loading"}>
                      {status === "loading" ? (
                        <><span className="tl-spin" aria-hidden="true" /> Sending…</>
                      ) : (
                        "Book a Discovery Call"
                      )}
                    </button>
                    <p className="tl-form-note">We'll only use your details to respond to your enquiry.</p>
                  </form>
                )}
              </div>
            </div>
          </div>
        </div>
      </section>

      <footer className="tl-foot">
        <div className="tl-wrap">
          <div className="tl-foot-in">
            <div style={{ maxWidth: "30ch" }}>
              <div className="tl-logo" style={{ marginBottom: 16 }}><img className="tl-logo-img" src={LOGO_SRC} alt="23Labs" /></div>
              <p style={{ fontSize: 15, color: "var(--ink-soft)" }}>Smarter systems, automation, and software for ambitious businesses.</p>
            </div>
            <div className="tl-foot-col"><h5>Studio</h5><a href="/services">Services</a><a href="#work">Work</a><a href="/about">About</a><a href="/contact">Contact</a></div>
            <div className="tl-foot-col"><h5>Products</h5><a href="#haylo">Haylo AI</a><a href="/contact">Let's have a chat</a></div>
            <div className="tl-foot-col"><h5>Connect</h5><a href="https://au.linkedin.com/company/23labs" target="_blank" rel="noopener noreferrer">LinkedIn</a><a href="https://www.instagram.com/_23labs.co_/" target="_blank" rel="noopener noreferrer">Instagram</a><a href="mailto:hello@23labs.co">hello@23labs.co</a></div>
          </div>
          <div className="tl-foot-bottom">
            <span>© 2026 23Labs Technologies. All rights reserved.</span>
          </div>
        </div>
      </footer>
    </div>
  );
}
